/** Semantic color slots that a named theme can override. */
export interface ThemeColors {
  /** App-wide background */
  background: string;
  /** App-wide foreground / text */
  foreground: string;
  /** Primary brand color */
  primary: string;
  /** Text on primary surfaces */
  primaryForeground: string;
  /** Accent surface color */
  accent: string;
  /** Text on accent surfaces */
  accentForeground: string;
