import { BUILT_IN_THEMES, type ThemeDefinition } from "@t3tools/shared/theme";
import { cn } from "~/lib/utils";

interface ThemeSelectorProps {
  activeThemeId: string | null;
  onSelect: (themeId: string) => void;
}

const SWATCH_KEYS = [
  "background",
  "sidebarBackground",
  "primary",
  "terminalBackground",
  "statusBarBackground",
] as const;

function ThemeCard({
  theme,
  selected,
  onSelect,
}: {
  theme: ThemeDefinition;
  selected: boolean;
  onSelect: () => void;
}) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      aria-label={theme.label}
      className={cn(
        "flex w-full flex-col gap-2.5 rounded-xl border p-3 text-left transition-colors",
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent",
      )}
      onClick={onSelect}
    >
      <div className="flex items-center gap-1.5">
        {SWATCH_KEYS.map((key) => (
          <span
            key={key}
            className="size-4 shrink-0 rounded-full border border-black/10"
            style={{ backgroundColor: theme.colors[key] }}
          />
        ))}
      </div>
      <div className="flex items-center justify-between gap-1">
        <span className="text-xs font-medium">{theme.label}</span>
        <span className="rounded bg-muted px-1 py-0.5 text-[10px] font-medium uppercase tracking-wide text-muted-foreground">
          {theme.base}
        </span>
      </div>
    </button>
  );
}

export function ThemeSelector({ activeThemeId, onSelect }: ThemeSelectorProps) {
  return (
    <div className="grid grid-cols-3 gap-3" role="radiogroup" aria-label="Color theme">
      {BUILT_IN_THEMES.map((theme) => (
        <ThemeCard
          key={theme.id}
          theme={theme}
          selected={activeThemeId === theme.id}
          onSelect={() => onSelect(theme.id)}
        />
      ))}
    </div>
  );
}

